+    requestId: request._id,
+    accountId: account?._id ?? request.accountId,
+    title: request.title,
+    status: request.expectedOutcome ?? READY_STATUS,
+    nextStep,
+    riskSignals,
+    approvers: ownerGroups.slice(),
+    approvalHistory: ownerGroups.map((group, index) => ({
